#include <stdio.h>
#include <math.h>
#include <stdlib.h>

/* Cache Configuration Structure */
typedef struct {
 int cache_size; /* Total cache size in bytes */
 int block_size; /* Block/line size in bytes */
 int num_lines; /* Number of cache lines */
 int associativity; /* 1 = direct, n = n-way, 0 = fully assoc */
 int offset_bits;
 int index_bits;
 int tag_bits;
} CacheConfig;

/* Result structure for mapping */
typedef struct {
 int tag;
 int index; /* For direct/set-assoc: line or set number */
 int offset;
 int way; /* For set-associative: which way (if hit) */
} AddressFields;

/* Initialize cache configuration */
CacheConfig init_cache(int cache_size_kb, int block_size_bytes, int associativity) {
 CacheConfig cache;

 cache.cache_size = cache_size_kb * 1024;
 cache.block_size = block_size_bytes;
 cache.associativity = associativity;
 cache.num_lines = cache.cache_size / cache.block_size;

 /* Calculate bit fields */
 cache.offset_bits = (int)(log2(block_size_bytes));

 if (associativity == 0) {
 /* Fully associative - no index */
 cache.index_bits = 0;
 cache.tag_bits = 32 - cache.offset_bits; /* Assuming 32-bit address */
 } else {
 int num_sets = cache.num_lines / associativity;
 cache.index_bits = (int)(log2(num_sets));
 cache.tag_bits = 32 - cache.index_bits - cache.offset_bits;
 }

 return cache;
}

/* Direct Mapped Cache Mapping */
AddressFields direct_mapped_access(CacheConfig cache, int address) {
 AddressFields result;

 result.offset = address % cache.block_size;
 result.index = (address / cache.block_size) % cache.num_lines;
 result.tag = address / (cache.block_size * cache.num_lines);
 result.way = 0;

 return result;
}

/* Set-Associative Cache Mapping */
AddressFields set_associative_access(CacheConfig cache, int address, int ways) {
 AddressFields result;
 int num_sets = cache.num_lines / ways;

 result.offset = address % cache.block_size;
 result.index = (address / cache.block_size) % num_sets;
 result.tag = address / (cache.block_size * num_sets);
 result.way = -1; /* Unknown at this point */

 return result;
}

/* Fully Associative Cache Mapping */
AddressFields fully_associative_access(CacheConfig cache, int address) {
 AddressFields result;

 result.offset = address % cache.block_size;
 result.tag = address / cache.block_size;
 result.index = -1; /* No index in fully associative */
 result.way = -1;

 return result;
}

/* Simulate cache with simple tag comparison */
int simulate_cache_access(CacheConfig cache, int *tags, int address, int associativity) {
 AddressFields fields;

 if (associativity == 1) {
 /* Direct mapped */
 fields = direct_mapped_access(cache, address);
 if (tags[fields.index] == fields.tag) {
 return 1; /* Hit */
 }
 /* Miss - load new block */
 tags[fields.index] = fields.tag;
 return 0; /* Miss */
 } 
 else if (associativity > 1) {
 /* Set-associative */
 fields = set_associative_access(cache, address, associativity);
 int num_sets = cache.num_lines / associativity;
 int set_start = fields.index * associativity;

 /* Search within the set */
 for (int i = 0; i < associativity; i++) {
 if (tags[set_start + i] == fields.tag) {
 return 1; /* Hit */
 }
 }
 /* Miss - replace first line (simplified FIFO) */
 tags[set_start] = fields.tag;
 return 0;
 }
 else {
 /* Fully associative - search all lines */
 fields = fully_associative_access(cache, address);

 for (int i = 0; i < cache.num_lines; i++) {
 if (tags[i] == fields.tag) {
 return 1; /* Hit */
 }
 }
 /* Miss - replace first line */
 tags[0] = fields.tag;
 return 0;
 }
}

/* Print address field breakdown */
void print_address_fields(char *mapping_type, AddressFields fields, int address) {
 printf("Address 0x%08X (%10d): ", address, address);
 printf("Tag=%5d, Index=%3d, Offset=%3d\n", 
 fields.tag, fields.index, fields.offset);
}

int main() {
 printf("========================================\n");
 printf(" CACHE MAPPING FUNCTION DEMO\n");
 printf("========================================\n\n");

 /* Configuration: 4KB cache, 64-byte blocks */
 CacheConfig cache = init_cache(4, 64, 1); /* Direct mapped */

 printf("Cache Configuration:\n");
 printf(" Size: %d KB\n", cache.cache_size / 1024);
 printf(" Block Size: %d bytes\n", cache.block_size);
 printf(" Number of Lines: %d\n", cache.num_lines);
 printf(" Tag Bits: %d\n", cache.tag_bits);
 printf(" Index Bits: %d\n", cache.index_bits);
 printf(" Offset Bits: %d\n\n", cache.offset_bits);

 /* Test addresses */
 int addresses[] = {0x1000, 0x1040, 0x2000, 0x2040, 0x10000, 0x10040};
 int num_addresses = 6;

 /* Direct Mapped */
 printf("--- Direct Mapped Cache ---\n");
 for (int i = 0; i < num_addresses; i++) {
 AddressFields fields = direct_mapped_access(cache, addresses[i]);
 print_address_fields("Direct", fields, addresses[i]);
 }

 /* 2-Way Set Associative */
 CacheConfig cache_2way = init_cache(4, 64, 2);
 int num_sets = cache_2way.num_lines / 2;

 printf("\n--- 2-Way Set Associative Cache (%d sets) ---\n", num_sets);
 for (int i = 0; i < num_addresses; i++) {
 AddressFields fields = set_associative_access(cache_2way, addresses[i], 2);
 printf("Address 0x%08X: Tag=%5d, Set=%3d, Offset=%3d\n",
 addresses[i], fields.tag, fields.index, fields.offset);
 }

 /* Fully Associative */
 CacheConfig cache_full = init_cache(4, 64, 0);

 printf("\n--- Fully Associative Cache ---\n");
 for (int i = 0; i < num_addresses; i++) {
 AddressFields fields = fully_associative_access(cache_full, addresses[i]);
 printf("Address 0x%08X: Tag=%7d, Offset=%3d (No Index)\n",
 addresses[i], fields.tag, fields.offset);
 }

 /* Simulate cache hit/miss */
 printf("\n--- Cache Hit/Miss Simulation ---\n");
 int *tags = (int *)calloc(cache.num_lines, sizeof(int));

 printf("Access sequence: ");
 for (int i = 0; i < num_addresses; i++) {
 printf("0x%X ", addresses[i]);
 }
 printf("\n");

 for (int i = 0; i < num_addresses; i++) {
 int result = simulate_cache_access(cache, tags, addresses[i], 1);
 printf("Access 0x%X: %s\n", addresses[i], result ? "HIT" : "MISS");
 }

 free(tags);
 return 0;
}
